return $input.all().map(item => {
  // Récupérer depuis le nœud précédent (Code in JavaScript)
  const sourceItem = $('Code in JavaScript').all()[item.pairedItem?.item ?? 0];
  const title = sourceItem?.json?.title || "Sans titre";
  const link = sourceItem?.json?.link || null;

  if (!item.json.choices || !item.json.choices[0]) {
    return { json: { title, link, resume: "Erreur de récupération", importance: "inconnue", tags: [] } };
  }

  const content = item.json.choices[0].message.content;
  try {
    const clean = content.replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(clean);
    return { json: { title, link, resume: parsed.resume || "Pas de résumé", importance: parsed.importance || "inconnue", tags: parsed.tags || [] } };
  } catch(e) {
    return { json: { title, link, resume: content || "Pas de résumé", importance: "inconnue", tags: [] } };
  }
});

return $input.all().map(item => {
  const importanceColor = {
    "haute": 15548997,   // rouge
    "moyenne": 16776960, // jaune
    "faible": 5763719    // vert
  };

  const color = importanceColor[item.json.importance?.toLowerCase()] || 5814783;

  return {
    json: {
      embeds: [{
        title: (item.json.title || "Sans titre").substring(0, 256),
        url: item.json.link || null,
        color: color,
        description: item.json.resume || "Pas de résumé",
        fields: [
          {
            name: "📊 Importance",
            value: item.json.importance || "Inconnue",
            inline: true
          },
          {
            name: "🏷️ Tags",
            value: (item.json.tags || []).join(", ") || "Aucun",
            inline: true
          }
        ],
        footer: { text: "Veille IA • OpenRouter + Serper" }
      }]
    }
  };
});
